class Solution { public int findMin(int[] nums) { int start = 0, end = nums.length - 1; while (start < end) { int mid = start + (end - start) / 2; if (nums[mid] > nums[end]) { start = mid + 1; } else { end = mid; } } return start; } public int search(int[] nums, int target) { int minEle = findMin(nums); if(nums[minEle]==target) return minEle; int ind =-1; if(minEle !=0){ ind = binary_search(nums,target, minEle, nums.length-1); } else { ind = binary_search(nums,target, 0, nums.length-1); } if(ind != -1) return ind; else return binary_search(nums, target ,0, minEle-1); } int binary_search(int[] nums, int target, int start, int end){ while( start <=end){ int mid = start + (end- start)/2; if(nums[mid]==target) return mid; else if( nums[mid] < target) start = mid +1; else end = mid-1; } return -1; } }